mapper.select:
SELECT * FROM note
WHERE user_id = #{userId}
  AND daily_note_date = #{dailyNoteDate}
LIMIT 1

SELECT * FROM note
WHERE user_id = #{userId}
  AND is_deleted = 0
  AND daily_note_date IS NOT NULL
  AND daily_note_date >= #{startDate}
  AND daily_note_date <= #{endDate}
ORDER BY daily_note_date ASC, update_time DESC

SELECT * FROM note
WHERE user_id = #{userId}
  AND folder_id = #{folderId}
  AND is_deleted = 0
ORDER BY update_time DESC

SELECT n.* FROM note n
JOIN note_tag t ON n.id = t.note_id
WHERE n.user_id = #{userId}
  AND n.is_deleted = 0
  AND t.tag_name = #{tagName}
ORDER BY n.update_time DESC

SELECT * FROM note
WHERE share_token = #{shareToken}
  AND is_deleted = 0

SELECT * FROM note
WHERE user_id = #{userId}
  AND is_deleted = 0
  AND update_time >= #{startTime}
ORDER BY update_time DESC

SELECT DISTINCT n.* FROM note n LEFT JOIN note_collaborator nc ON n.id = nc.note_id JOIN note_tag t ON n.id = t.note_id WHERE n.is_deleted = 0 AND (n.user_id = #{userId} OR nc.user_id = #{userId}) AND t.tag_name IN
#{tag}
ORDER BY n.update_time DESC

mapper.update:
UPDATE note
SET folder_id = NULL
WHERE user_id = #{userId}
  AND folder_id = #{folderId}
  AND is_deleted = 1
